%[text] # Panel models with cross sections
%[text] Tutorial file for testing panel model
%[text:tableOfContents]{"heading":"**Table of Contents**"}
%%
%[text] ## Housekeeping
clear
close all

import cross.*
%%
%[text] ## Convenience functions
%[text] 
percentiles = [10, 50, 90];

prctileFunc = @(x) prctile(x, percentiles, 2);

extremesFunc = @(x) [min(x, [], 2), max(x, [], 2)];

medianFunc = @(x) median(x, 2);

flatFunc = @(x) x(:, :);

defaultColors = get(0, "defaultAxesColorOrder");
%%
%[text] ## Number of Samples
numPresampled = 100;
%%
%[text] ## Prepare meta information for the models
%[text] 
%[text] Note that the meta information is common to all cross-section panel BVAR models, regardless of the specific estimator used.
%[text] The properties are as follows:
%[text] **endogenousConcepts** –  a list of endogenous variables, listed without the country suffix. Plays the same role as **endogenousNames** in plain BVARs
%[text] **units** – a list of countries/units that share the same endogenous variables

estimStart = datex("1972-Q1");
estimEnd = datex("2014-Q4");
estimSpan = datex.span(estimStart, estimEnd);

meta = Meta( ...
    endogenousConcepts=["YER", "HICSA", "STN"], ...
    units=["US", "EA", "UK"], ...
    exogenous=["Oil"], ...
    order=4, ...
    intercept=true, ...
    estimationSpan=estimSpan, ...
    identificationHorizon=20, ...
    shockConcepts=["DEM", "SUP", "POL"] ...
);


%%
%[text] ## Specifying and loading input data

inputTbl = tablex.fromFile("data/panel_data.csv");
dataH = DataHolder(meta, inputTbl);
%[text] ## 
%%
%[text] ## Reduced form models
%[text] There are some common properties for the cross section panel BVARs. Which are
%[text] 
%[text] **Alpha0 (1000)** – The shape of the Inverse Gamma distribution of residual variances
%[text] **Delta0 (1)** – The scale of the Inverse Gamma distribution of residual variances
%[text] #### 
%[text] #### Static Cross Panel
%[text] 
estimatorR1 = estimator.StaticCrossPanel(meta);
%[text] ### 
%[text] #### Dynamic Cross Panel
%[text] 
%[text] **A0 (1000)** – The shape of the Inverse Gamma distribution of factor variances
%[text] **B0 (1)** – The scale of the Inverse Gamma distribution of factor variances
%[text] **Rho (0.75)** – The AR coefficient in the prior for factor coefficients.
%[text] **Gamma (0.85)** – The AR coefficient for latent innovation series
%[text] 
% estimatorR1 = estimator.DynamicCrossPanel(meta);
%[text] 
%[text] ### Creating the reduced form model

modelR1 = ReducedForm( ...
    meta=meta, ...
    dataHolder=dataH, ...
    estimator=estimatorR1 ...
);
%%
%[text] ## Estimation/sampling of the reduced form model 

modelR1.initialize();
info0 = modelR1.presample(numPresampled); %[output:5ccee59e]
modelR1.Presampled{1}.beta %[output:6fd84f1d]
%[text] 
%%
%[text] ## Running Unconditional forecast 
%[text] 
%[text] ### Setting up the forecast range and run the forecast
fcastStart = datex.shift(modelR1.Meta.EstimationEnd, -10); %The forecast starts 10 periods prior to the end of the estimation span.
fcastEnd = datex.shift(modelR1.Meta.EstimationEnd, 0); %The forecast ends at the end of the estimation window.
fcastSpan = datex.span(fcastStart, fcastEnd);

fcastStart, fcastEnd %[output:0d12f1f5] %[output:57037866]

fcastTbx = modelR1.forecast(fcastSpan);
fcastPrctileTbx = tablex.apply(fcastTbx, prctileFunc);
fcastPrctileTbx = tablex.flatten(fcastPrctileTbx); %keeping only the pctiles set at the beginning of the file (10, 50, 90)

%[text] ### Visualize the unconditional forecast

chartpack.forecastPercentiles( ... %[output:group:4262c444] %[output:9b1256b7] %[output:7d6e38bb] %[output:1e318b85] %[output:270aca15]
    fcastPrctileTbx, modelR1, FigureTitle ="Unconditional forecast") %[output:group:4262c444] %[output:9b1256b7] %[output:7d6e38bb] %[output:1e318b85] %[output:270aca15]
%%
%[text] ## Identification
%[text] ### Cholesky
%[text] #### Setting up the identifier
identChol = identifier.Cholesky(order=[]);

modelS1 = Structural(reducedForm=modelR1, identifier=identChol);
modelS1.initialize();

info1 = modelS1.presample(numPresampled); %[output:1c3579a8]
modelS1.Presampled{1} %[output:58d3c5f1]
%[text] #### 
%[text] #### Checking transition matrices
modelS1.Presampled{1}.IdentificationDraw %[output:69b9a24c]
modelS1.Presampled{1}.IdentificationDraw.A{1,1} %[output:8909ffd8]
modelS1.Presampled{1}.IdentificationDraw.A{2,1} %[output:4eb0fae3]
%[text] #### 
%[text] #### Checking scaling matrix
modelS1.Presampled{1}.D %[output:88255948]
modelS1.Presampled{2}.D %[output:1d7282da]

%%
%[text] ## Impulse responses (IRF)
%[text] ### Cholesky
respTbl1 = modelS1.simulateResponses(); %[output:4023b2fa]
respTbl1 = tablex.apply(respTbl1, prctileFunc);
respTbl1 = tablex.flatten(respTbl1);

respTbl1 %[output:4a98a812]
chartpack.responsePercentiles( ... %[output:group:9d00f31b] %[output:843a6529] %[output:59f96367] %[output:3fd5561b] %[output:06c03c93] %[output:74ddc46c] %[output:54c1ff42] %[output:24069641] %[output:3582070b] %[output:73fa4687]
    respTbl1, modelS1 ... %[output:843a6529] %[output:59f96367] %[output:3fd5561b] %[output:06c03c93] %[output:74ddc46c] %[output:54c1ff42] %[output:24069641] %[output:3582070b] %[output:73fa4687]
    , "figureTitle", "Shock responses (percentiles)" ... %[output:843a6529] %[output:59f96367] %[output:3fd5561b] %[output:06c03c93] %[output:74ddc46c] %[output:54c1ff42] %[output:24069641] %[output:3582070b] %[output:73fa4687]
); %[output:group:9d00f31b] %[output:843a6529] %[output:59f96367] %[output:3fd5561b] %[output:06c03c93] %[output:74ddc46c] %[output:54c1ff42] %[output:24069641] %[output:3582070b] %[output:73fa4687]
%%
%[text] ## **Historical shock decomposition**
%[text] 

histContTbx = modelS1.calculateContributions();

tablex.getHigherDims(histContTbx) %[output:189674f8]

histContMedTbx = tablex.apply(histContTbx, medianFunc);

chartpack.contributionsMedian( ... %[output:group:627fed4b] %[output:7299e99c]
    histContMedTbx, modelS1 ... %[output:7299e99c]
    , "figureTitle", "Shock contributions with Cholesky (median)" ... %[output:7299e99c]
); %[output:group:627fed4b] %[output:7299e99c]
%%
%[text] ## **Unconditional forecast shock decomposition**
%[text] 

[uncFcastTbl1, uncFcastContribTbl1] = modelS1.forecast( ...
    fcastSpan, ...
    contributions=true ...
);

tablex.getHigherDims(uncFcastContribTbl1) %[output:8cd4ccd1]

contMedTbx = tablex.apply(uncFcastContribTbl1, medianFunc);
contMedTbx = tablex.apply(contMedTbx, flatFunc);

chartpack.contributionsMedian( ... %[output:group:56eb2eed] %[output:817b7fca]
    contMedTbx,modelS1 ... %[output:817b7fca]
    , "figureTitle", "Unconditional forecast Shock contributions (median)" ... %[output:817b7fca]
); %[output:group:56eb2eed] %[output:817b7fca]

%%
%[text] ## **FEVD**

fevdTbx = modelS1.calculateFEVD(); %[output:38863ebf]

tablex.getHigherDims(fevdTbx) %[output:9f5b4940]

fevdMedTbx = tablex.apply(fevdTbx, medianFunc);
fevdMedTbx = tablex.apply(fevdMedTbx, flatFunc);

chartpack.contributionsMedian( ... %[output:group:191dc4cd] %[output:374089fc]
    fevdMedTbx,modelS1 ... %[output:374089fc]
    , "figureTitle", "FEVD (median)" ... %[output:374089fc]
); %[output:group:191dc4cd] %[output:374089fc]
%%
%[text] ## Conditional forecast
%[text] 
%[text] ### Setting up the conditions and the forecast plan
condDataTbl = tablex.fromFile("data/condDataTblPanel.xlsx");
planTbl = tablex.readConditioningPlan("data/planTblPanel.xlsx");
%[text] ### 
%[text] ### Setting up the forecast range 
cfcastStart = datex.shift(modelR1.Meta.EstimationEnd, 1); %The forecast starts after the estimation span.
cfcastEnd = datex.shift(modelR1.Meta.EstimationEnd, 12); 
cfcastSpan = datex.span(cfcastStart, cfcastEnd);
%[text] ### 
%[text] ### Running conditional forecast with no simulation plan
[condFcastTbl1, condFcastContribTbl1] = modelS1.conditionalForecast( ... %[output:group:84222309] %[output:4aebf3a3]
    cfcastSpan, ... %[output:4aebf3a3]
    conditions=condDataTbl, ... %[output:4aebf3a3]
    plan=[], ... %[output:4aebf3a3]
    exogenousFrom = "conditions" ... %[output:4aebf3a3]
); %[output:group:84222309] %[output:4aebf3a3]

condFcastPrctilesTbl1 = tablex.apply(condFcastTbl1, prctileFunc);
%[text] ### 
%[text] ### Running conditional forecast with simulation plan
[condFcastTbl2, condFcastContribTbl2] = modelS1.conditionalForecast( ... %[output:group:1c80a522] %[output:72294cc2]
    cfcastSpan, ... %[output:72294cc2]
    conditions=condDataTbl, ... %[output:72294cc2]
    plan=planTbl, ... %[output:72294cc2]
    exogenousFrom = "conditions" ... %[output:72294cc2]
); %[output:group:1c80a522] %[output:72294cc2]

condFcastPrctilesTbl2 = tablex.apply(condFcastTbl2, prctileFunc);
%[text] ### 
%[text] ### Visualize the conditional forecast
chartpack.conditionalForecastPercentiles( ... %[output:group:9ebaeec6] %[output:1a9c6343] %[output:6e8f3397] %[output:17481156]
    condFcastPrctilesTbl1,modelS1 ... %[output:1a9c6343] %[output:6e8f3397] %[output:17481156]
    , "figureTitle", "Conditional forecast w/o plan (percentiles)" ... %[output:1a9c6343] %[output:6e8f3397] %[output:17481156]
); %[output:group:9ebaeec6] %[output:1a9c6343] %[output:6e8f3397] %[output:17481156]

chartpack.conditionalForecastPercentiles( ... %[output:group:7cd1a7c7] %[output:1773cb7d] %[output:9407d118] %[output:91874b52]
    condFcastPrctilesTbl2,modelS1 ... %[output:1773cb7d] %[output:9407d118] %[output:91874b52]
    , "figureTitle", "Conditional forecast with plan (percentiles)" ... %[output:1773cb7d] %[output:9407d118] %[output:91874b52]
); %[output:group:7cd1a7c7] %[output:1773cb7d] %[output:9407d118] %[output:91874b52]


